using sv_fd865137d23c41778d56aab4c98d624a.Models;

namespace sv_fd865137d23c41778d56aab4c98d624a.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 30),
            new(2, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan, finished with Parmigiano-Reggiano.", 45),
            new(3, "Tiramisu", "Layered dessert of espresso-soaked ladyfingers and mascarpone cream.", 25),
        },
        [2] = new List<Recipe>
        {
            new(4, "Pad Thai", "Stir-fried rice noodles with shrimp, tofu, peanuts, and tamarind sauce.", 20),
            new(5, "Green Curry", "Aromatic coconut milk curry with Thai basil, bamboo shoots, and chicken.", 35),
            new(6, "Tom Yum Soup", "Hot and sour soup with lemongrass, galangal, kaffir lime leaves, and prawns.", 25),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion on corn tortillas.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime juice, cilantro, jalapeño, and tomato.", 10),
            new(9, "Enchiladas Rojas", "Corn tortillas filled with chicken, rolled and covered in red chili sauce.", 50),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_fd865137d23c41778d56aab4c98d624a.Models
@using sv_fd865137d23c41778d56aab4c98d624a.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@implements IDisposable

<PageTitle>Recipes</PageTitle>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <ul>
        @foreach (var recipe in GetSortedRecipes())
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <br /><small>Prep time: @recipe.PrepTimeMinutes min</small>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            // Only sort changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request for a previous cuisine.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var cancellationToken = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;

        var cuisineId = CuisineId;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(cuisineId, cancellationToken);

            cancellationToken.ThrowIfCancellationRequested();

            _recipes = result;
            _loadedCuisineId = cuisineId;
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // Request was superseded or component disposed — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return Enumerable.Empty<Recipe>();

        return Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes.OrderByDescending(r => r.Id),
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes,
        };
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

