            new(5, "Green Curry", "Aromatic coconut milk curry with Thai basil, bamboo shoots, and chicken.", 35),
            new(6, "Tom Yum Soup", "Hot and sour soup with lemongrass, galangal, kaffir lime leaves, and prawns.", 25),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion on corn tortillas.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime juice, cilantro, jalapeño, and tomato.", 10),
            new(9, "Enchiladas Rojas", "Corn tortillas filled with chicken, rolled and covered in red chili sauce.", 50),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
